import React from 'react'
import logo from '../../assets/images/logo1.png'
import CB1 from '../../assets/images/discussion-1.png'
import CB2 from '../../assets/images/place-1.png'
import CB3 from '../../assets/images/information-1.png'
import CB4 from '../../assets/images/target-1.png'
import CB5 from '../../assets/images/Frame5.png'
import CB6 from '../../assets/images/Frame6.png'
import CB7 from '../../assets/images/Frame7.png'
import CB8 from '../../assets/images/Frame8.png'
import Elipse from '../../assets/images/Ellips.png'
import Elipse2 from '../../assets/images/Ellips2.png'
import { Link } from "react-router-dom";
import ApiRequest from '../../Services/ApiRequest'
import { APP_URL } from '../../Helpers/AppConstant'
import Header from "../../Components/Layouts/Header"
import Footer from "../../Components/Layouts/Footer"

class MySpace extends React.Component {

    state = {
        isAnimationLoaded: false,
        spaces: []
    }

    componentDidMount = async () => {
        const response = await ApiRequest.getRequest('/getSpaces');
        if (response.status === 200 && response.data.spaces.length !== 0) {
            this.setState({
                spaces: response.data.spaces
            })
        }
    }

    spacesCardHtml() {
        if (this.state.spaces) {
            return (
                this.state.spaces.map(el => {
                    console.log(el);
                    return (
                        <div className="col-md-6">
                            <div className="row mar-width-0 browse-section">
                                <div className="col-1 browse-section-inner-1">
                                    <img src={APP_URL + el.icon} className="cb1" alt="" />
                                </div>
                                <div className="col-11 browse-section-inner-2">
                                    <h3>{el.title}</h3>
                                    <p>{el.summary}</p>
                                    <div className="text-center"> <img src={APP_URL + el.image} className="cb5" alt="" /></div>
                                    <Link to="/FindMentor" className="get-browse-btn">My Mentors</Link>
                                </div>
                            </div>
                        </div>
                    );
                })
            );
        }
    }

    render() {
        console.log(this.spacesCardHtml)
        return (
            <>
                <Header />
                <div className="container-fluid browse-wrapper p-0">


                    <div className="container pb-4 pt-5">
                        <div className="col-md-12 works-inner-1">
                            <h2>My Space: Project Management</h2>
                        </div>
                        <div className="row mar-width-0">
                            {this.spacesCardHtml()}
                        </div>
                    </div>
                </div>

                <Footer />
            </>

        )
    }
}

export default MySpace
